import Nav from "@/components/Nav";

export default function RootLayout({ children }) {
  return (
    <html lang="en">
      <body>

        <Session>

          <Nav />

          <AuthWrapper>
            <main className="min-h-screen bg-gray-100">
              {children}
            </main>
          </AuthWrapper>

          <ToastContainer
            position="bottom-center"
            autoClose={3000}
            theme="light"
          />

        </Session>

      </body>
    </html>
  );
}